{
  "dialogue_segments": [
    {
      "index": 0,
      "speaker": "Speaker 1",
      "speaker_id": "spk_001",
      "text": "They want you afraid.",
      "confidence": 0.5
    },
    {
      "index": 1,
      "speaker": "Speaker 1",
      "speaker_id": "spk_001",
      "text": "Fear makes you easier to control.",
      "confidence": 0.5
    },
    {
      "index": 2,
      "speaker": "Speaker 1",
      "speaker_id": "spk_001",
      "text": "It's time to wake up.",
      "confidence": 0.5
    },
    {
      "index": 3,
      "speaker": "Speaker 1",
      "speaker_id": "spk_001",
      "text": "Your streets shall once again run red with your blood.",
      "confidence": 0.5
    },
    {
      "index": 4,
      "speaker": "Speaker 2",
      "speaker_id": "spk_002",
      "text": "Raul Menendez ignited global unrest on an unprecedented scale.",
      "confidence": 0.5
    },
    {
      "index": 5,
      "speaker": "Speaker 2",
      "speaker_id": "spk_002",
      "text": "Menendez is a terrorist. We're bringing peace and security to the world.",
      "confidence": 0.5
    },
    {
      "index": 6,
      "speaker": "Speaker 3",
      "speaker_id": "spk_003",
      "text": "He refuses to let me go.",
      "confidence": 0.5
    },
    {
      "index": 7,
      "speaker": "Speaker 4",
      "speaker_id": "spk_004",
      "text": "Stop looking backwards, David, but matters is what we do next.",
      "confidence": 0.5
    },
    {
      "index": 8,
      "speaker": "Speaker 4",
      "speaker_id": "spk_004",
      "text": "A lot of people counting on us for answers.",
      "confidence": 0.5
    },
    {
      "index": 9,
      "speaker": "Speaker 3",
      "speaker_id": "spk_003",
      "text": "This isn't real.",
      "confidence": 0.5
    },
    {
      "index": 10,
      "speaker": "Speaker 4",
      "speaker_id": "spk_004",
      "text": "The hell it isn't!",
      "confidence": 0.5
    },
    {
      "index": 11,
      "speaker": "Speaker 5",
      "speaker_id": "spk_005",
      "text": "Obey your master... Master... Just call me faster... Master... Master... The master's puppet's a puppet's brain... Twisting your mind, smashing your day... Blinding from me, you can't see... Just go ahead, it's all in your head... Master, master... Plans and dreams are now in the after... Master, master... You'll be in my grasp...",
      "confidence": 0.4
    },
    {
      "index": 12,
      "speaker": "Speaker 6",
      "speaker_id": "spk_006",
      "text": "Pull it together, man.",
      "confidence": 0.5
    },
    {
      "index": 13,
      "speaker": "Speaker 4",
      "speaker_id": "spk_004",
      "text": "So eager to leave, David?",
      "confidence": 0.5
    },
    {
      "index": 14,
      "speaker": "Speaker 4",
      "speaker_id": "spk_004",
      "text": "Killing a man is a hell of a lot easier than killing an idea.",
      "confidence": 0.5
    },
    {
      "index": 15,
      "speaker": "Speaker 4",
      "speaker_id": "spk_004",
      "text": "You were never cut out to be a Mason.",
      "confidence": 0.5
    },
    {
      "index": 16,
      "speaker": "Speaker 4",
      "speaker_id": "spk_004",
      "text": "No more games. This ends now.",
      "confidence": 0.5
    },
    {
      "index": 17,
      "speaker": "Speaker 7",
      "speaker_id": "spk_007",
      "text": "Get the Reznov challenge pack when you pre-order now.",
      "confidence": 0.5
    }
  ],
